"use client";

import * as React from "react";
import { ArrowLeft, ArrowRight } from "lucide-react";
import { FieldValues, useFormContext } from "react-hook-form";
import { ZodProvider } from "@acp-autoform/zod";
import * as z from "zod";

import { AutoForm } from "@/components/ui/autoform";
import { Button } from "@/components/ui/button";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface MultistepFormStep {
  label: string;
  schema: z.ZodObject<any>;
  defaults: FieldValues;
}

export interface MultistepFormProps {
  steps: MultistepFormStep[];
  onSubmit: (values: FieldValues) => void;
}

// ---------------------------------------------------------------------------
// StepActions validates the current form then fires onNext / onBack
// ---------------------------------------------------------------------------

function StepActions<T extends FieldValues>({
  isBack,
  isNext,
  onBack,
  onNext,
}: {
  isBack: boolean;
  isNext: boolean;
  onBack: () => void;
  onNext: (values: T) => void;
}) {
  const { trigger, getValues } = useFormContext<T>();

  const handleNext = async () => {
    const isValid = await trigger(undefined, { shouldFocus: true });

    if (isValid) {
      onNext(getValues());
    }
  };

  return (
    <div className="flex gap-2">
      {isBack && (
        <Button
          type="button"
          variant="outline"
          className="gap-2"
          onClick={() => onBack()}
        >
          <ArrowLeft className="h-4 w-4" />
          Back
        </Button>
      )}
      <Button type="submit" className="gap-2" onClick={handleNext}>
        {isNext ? "Next" : "Submit"}
        {isNext && <ArrowRight className="h-4 w-4" />}
      </Button>
    </div>
  );
}

// ---------------------------------------------------------------------------
// MultistepForm
// ---------------------------------------------------------------------------

export function MultistepForm({ steps, onSubmit }: MultistepFormProps) {
  const [step, setStep] = React.useState(0);
  const [values, setValues] = React.useState<Record<number, FieldValues>>(() =>
    Object.fromEntries(steps.map((s, i) => [i, { ...s.defaults }])),
  );

  const providers = React.useMemo(
    () => steps.map((s) => new ZodProvider(s.schema)),
    [steps],
  );

  const isLastStep = step === steps.length - 1;
  const currentStep = steps[step];

  const saveAndAdvance = (stepIndex: number, stepValues: FieldValues) => {
    const next = { ...values, [stepIndex]: stepValues };
    setValues(next);

    if (isLastStep) {
      onSubmit(next);
    } else {
      setStep(stepIndex + 1);
    }
  };

  return (
    <div className="space-y-4">
      {/* Breadcrumb */}
      <div className="flex flex-wrap items-center gap-2 text-sm text-muted-foreground">
        {steps.map((s, i) => (
          <React.Fragment key={s.label}>
            <span className={step === i ? "font-medium text-foreground" : ""}>
              {s.label}
            </span>
            {i < steps.length - 1 && <ArrowRight className="h-4 w-4" />}
          </React.Fragment>
        ))}
      </div>

      {/* Active step form */}
      {currentStep && (
        <AutoForm
          key={currentStep.label}
          schema={providers[step]}
          defaultValues={values[step]}
        >
          <StepActions
            isBack={step > 0}
            isNext={!isLastStep}
            onBack={() => step > 0 && setStep(step - 1)}
            onNext={(v: FieldValues) => saveAndAdvance(step, v)}
          />
        </AutoForm>
      )}
    </div>
  );
}

"use client";

import * as React from "react";
import { FieldValues } from "react-hook-form";
import * as z from "zod";

import { MultistepForm, MultistepFormStep } from "@/components/multistep-form";

// ---------------------------------------------------------------------------
// Step definitions
// ---------------------------------------------------------------------------

const STEPS: MultistepFormStep[] = [
  {
    label: "Contact",
    schema: z.object({
      fullName: z.string().min(2, "Enter your name"),
      email: z.email("Enter a valid email"),
    }),
    defaults: { fullName: "", email: "" },
  },
  {
    label: "Account",
    schema: z.object({
      username: z.string().min(3, "Use at least 3 characters"),
      password: z.string().min(8, "Use at least 8 characters"),
    }),
    defaults: { username: "", password: "" },
  },
  {
    label: "Address",
    schema: z.object({
      street: z.string().min(3, "Enter your street address"),
      city: z.string().min(2, "Enter your city"),
    }),
    defaults: { street: "", city: "" },
  },
  {
    label: "Preferences",
    schema: z.object({
      newsletter: z.boolean().default(false),
      notes: z.string().min(5, "Add a short note"),
    }),
    defaults: { newsletter: false, notes: "" },
  },
];

// ---------------------------------------------------------------------------
// Demo uses MultistepForm
// ---------------------------------------------------------------------------

export default function MultistepFormDemo() {
  const [submitted, setSubmitted] = React.useState<FieldValues | null>(null);

  return (
    <div className="grid gap-4 rounded-lg border bg-background p-6 md:grid-cols-[1fr_220px]">
      <MultistepForm steps={STEPS} onSubmit={setSubmitted} />

      <div className="rounded-md border bg-secondary/50 p-4 text-sm">
        <div className="font-medium">Submitted value</div>
        <pre className="mt-3 overflow-auto text-xs">
          {JSON.stringify(submitted, null, 2)}
        </pre>
      </div>
    </div>
  );
}
